SELECT
c.*,
a.name as algorithm_name,
u.username as created_by_name
FROM vls_container_instance c
LEFT JOIN vls_algorithm a ON c.algorithm_id = a.id AND a.is_deleted = 0
WHERE c.is_deleted = 0

    AND c.instance_name LIKE CONCAT('%', #{query.instanceName}, '%')


    AND c.container_id LIKE CONCAT('%', #{query.containerId}, '%')


    AND c.image_name LIKE CONCAT('%', #{query.imageName}, '%')


    AND c.algorithm_id = #{query.algorithmId}


    AND c.instance_type = #{query.instanceType}


    AND c.instance_status = #{query.instanceStatus}


    AND c.health_status = #{query.healthStatus}


    AND c.create_user = #{query.createdBy}


    AND c.create_time >= #{query.createdTimeStart}


    AND c.create_time <= #{query.createdTimeEnd}


    AND c.start_time >= #{query.startTimeStart}


    AND c.start_time <= #{query.startTimeEnd}



        ORDER BY c.${query.orderBy} ${query.order}


        ORDER BY c.create_time DESC
